import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { ExpansionPanel, ExpansionPanelSummary, ExpansionPanelDetails, Chip, Button, Popover, TextField, FormControl, Typography, FormLabel, ButtonGroup } from '@material-ui/core';
import { MyTable, EditableCellMapFormat, MyDialog } from '../../../../includes';
import { colors } from '../../../../../utils';
import { appActions, alertAction } from '../../../../../actions';
import { OptionNameEdit } from './OptionNameEdit';
import { productStrings } from '../../config';
import { productActions } from '../../actions';
import { DescriptionOptionValueBox } from './DescriptionOptionValueBox';


const style = theme => ({
    root: {
    }
})

class _ItemDescriptions extends Component {
    constructor(props) {
        super(props);
        this.state = {
            descriptionUnusuable : null,
            description : null,
            editMode : true,
            newDescriptionName : "",
            newDescriptionDialog : false,
        }
        this.optionNameContexts = {};
        this.optionValueContexts = {}
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        productActions.getProductDescriptions()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const { 
            [productStrings.productDescriptions] : description,
        }= props;
        if(!state.descriptionUnusuable && description){
            state.description = state.descriptionUnusuable = description
        }else if(JSON.stringify(state.descriptionUnusuable) !==
        JSON.stringify(description)){
            state.description = state.descriptionUnusuable = description;
        }
        return state;
    }
    getOptionNameContexts = (descriptionIndex, optionId, isNew) => (context) => {
        if(!isNew){
            if(this.optionNameContexts[descriptionIndex]){
                this.optionNameContexts[descriptionIndex] = { [optionId] : context};
            }else this.optionNameContexts = {
                [descriptionIndex] : {
                    [optionId] : context
                }
            };
        }else {
            if(this.optionNameContexts[descriptionIndex])
                this.optionNameContexts[descriptionIndex].new = context;
            else this.optionNameContexts = {
                [descriptionIndex] : {
                    new : context
                }
            }
        }
    }
    getOptionValueContext = (descriptionIndex, optionId, isNew) => context => {
        if(!isNew){
            if(this.optionValueContexts[descriptionIndex]){
                this.optionValueContexts[descriptionIndex] = { [optionId] : context};
            }else this.optionValueContexts = {
                [descriptionIndex] : {
                    [optionId] : context
                }
            };
        }else {
            if(this.optionValueContexts[descriptionIndex])
                this.optionValueContexts[descriptionIndex].new = context;
            else this.optionValueContexts = {
                [descriptionIndex] : {
                    new : context
                }
            }
        }
    }
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>
    tableCellContentView = (descriptionIndex) => (editMode, {row, cellMap}) => {
        const {classes} = this.props;
        if(editMode){
            const optionType = row._id ? "_id" : "id";
            switch(cellMap){
                case "name" : 
                    return <OptionNameEdit
                            data={row[cellMap]}
                            getContext={this.getOptionNameContexts(descriptionIndex, row[optionType], row.new)}/>
                case "values" :
                    return <DescriptionOptionValueBox
                                row={row}
                                cellMap={cellMap}
                                getContext={this.getOptionValueContext(descriptionIndex, row[optionType], row.new)}
                                />
                    
            }
        }else{
            switch(cellMap){
                case "name" : return row[cellMap];
                case "values" : return <Fragment>
                    {row[cellMap] && row[cellMap].map((item, index)=>{
    
                        return <Chip key={index} label={item.name}/>
                    })}
                </Fragment>
            }
        }
    }
    editBtnHandler = (descriptionIndex) => row => () => {
        let description = [...this.state.description];
        let optionType = row._id ? "_id" : "id";
        const { item : optionItem, index : optionIndex } = 
            description[descriptionIndex].options.getFirstObjectByPropValue(optionType, row[optionType]);
        if(optionItem){
            description[descriptionIndex].options[optionIndex].editing = true;
        }
        this.setState({description});
    }
    cancelEditBtnHandler = (descriptionIndex) => row => () =>{
        let description = [...this.state.description];
        let optionType = row._id ? "_id" : "id";
        const { item : optionItem, index : optionIndex } = 
            description[descriptionIndex].options.getFirstObjectByPropValue(optionType, row[optionType]);
        if(optionItem){
            delete description[descriptionIndex].options[optionIndex].editing;
        }
        this.setState({description});
    }
    deleteBtnHandler = (descriptionIndex) => row => () => {
        let description = [...this.state.description];
        let optionType = row._id ? "_id" : "id";
        const { item : optionItem, index : optionIndex } = 
            description[descriptionIndex].options.getFirstObjectByPropValue(optionType, row[optionType]);
        if(optionItem){
            delete description[descriptionIndex].options.splice(optionIndex, 1);
        }
        this.setState({description});
    }
    addButtonHandler = (descriptionIndex) => length => () => {
        const {dispatch} = this.props;
        let optionName;
        if(this.optionNameContexts[descriptionIndex] &&
        this.optionNameContexts[descriptionIndex].new &&
        this.optionNameContexts[descriptionIndex].new.state.data !== ""){
            optionName = this.optionNameContexts[descriptionIndex].new.state.data;
        }else{
            appActions.showSnackbar(
                alertAction.error("option name is missing")
            )(dispatch);
            return;
        }
        let optionValues;
        if(this.optionValueContexts[descriptionIndex] &&
        this.optionValueContexts[descriptionIndex].new &&
        this.optionValueContexts[descriptionIndex].new.state.list){
            optionValues = this.optionValueContexts[descriptionIndex].new.state.list;
        }else{
            appActions.showSnackbar(
                alertAction.error("There is no values for the option")
            )(dispatch);
            return;
        }
        let {description} = this.state;
        description = description ? [...description] : [];
        if(description[descriptionIndex] && 
            description[descriptionIndex].options &&
            description[descriptionIndex].options.length !== 0){
            const options = description[descriptionIndex].options;
            const lastOptionId = options[options.length - 1].id || 0;
            description[descriptionIndex].options.push({
                id : lastOptionId + 1,
                name : optionName,
                values : optionValues
            });            
        }else description[descriptionIndex].options = [{
            id : 1,
            name : optionName,
            values : optionValues
        }]
        this.setState({description});
    }
    newDescriptionContinueBtnHandler(){
        const {newDescriptionName} = this.state;
        if(!newDescriptionName || newDescriptionName === ""){
            appActions.showSnackbar(
                alertAction.error("Empty field")
            )(this.props.dispatch);
            return;
        }
        this.addNewDescription(newDescriptionName);
        this.setState({newDescriptionDialog : false});
    }
    addNewDescription(name){
        let {description} = this.state;
        description = description ? [...description] : [];
        const lastDescriptionIndex = description[description.length - 1].id || 0;
        description.push({
            _id : lastDescriptionIndex + 1,
            name
        })
        this.setState({description});
    }
    newDescriptionOnChange(e){
        const value = e.target.value;
        this.setState({newDescriptionName : value});
    }
    render() {
        const {classes,
            [productStrings.itemConfigEditMode] : editMode
        } = this.props;
        let { description, newDescriptionName, newDescriptionDialog} = this.state;
        let header = ["Names", "Values"];
        let dataMap = ["name", "values"];
        if(editMode){
            header.push("Actions");
            dataMap.push("action");
        }
        return (
            <div className={classes.root}>
                {editMode && <div className={classes.newDescription}>
                    <Button 
                        onClick={()=>this.setState({newDescriptionDialog: true})}
                        style={{backgroundColor : colors.secondary, color : colors.white}}>
                        New Description
                    </Button>
                </div>}
                <MyDialog 
                    open={newDescriptionDialog}>
                    <FormLabel>New Description</FormLabel>
                    <FormControl>
                        <TextField
                            label="Description Category Name"
                            placeholder="Name"
                            margin="normal"
                            value={newDescriptionName}
                            onChange={e=>this.newDescriptionOnChange(e)}/>
                    </FormControl>
                    <FormControl style={{flexDirection: "row"}}>
                            <Button 
                                style={{margin: 5}}
                                variant="outlined"
                                color="secondary" 
                                onClick={()=>this.setState({newDescriptionDialog: false})}>
                                    Cancel
                            </Button>
                            <Button 
                                style={{margin: 5}}
                                variant="outlined"
                                color="primary" 
                                onClick={()=>this.newDescriptionContinueBtnHandler()}>
                                    Continue
                            </Button>
                    </FormControl>
                </MyDialog>
                {description && description.map((item, index)=>{ 
                    let {options} = item;
                    options = options ? [...options] : [];
                    if(editMode){
                        options = options ?
                        [...options.map(
                            item=>({...item, editable : true, delible :true})
                        ), {new : true}] : 
                        [{new : true}];
                    }
                    return <ExpansionPanel expanded={true} key={index}>
                        <ExpansionPanelSummary>
                            {item.name}
                        </ExpansionPanelSummary>
                        <ExpansionPanelDetails style={{
                            backgroundColor : colors.gainsboro,
                            padding : 0,
                        }}>
                            <MyTable
                                elevation={0}
                                header={header}
                                dataMap={dataMap}
                                data={options}
                                CellMap={this.cellMapFormat({
                                    addButtonHandler : this.addButtonHandler(index),
                                    tableCellContentView : this.tableCellContentView(index),
                                    editBtnHandler : this.editBtnHandler(index),
                                    cancelEditBtnHandler : this.cancelEditBtnHandler(index),
                                    deleteBtnHandler : this.deleteBtnHandler(index),
                                })}
                                />
                        </ExpansionPanelDetails>
                    </ExpansionPanel>
                

                })}
            </div>
        );
    }
}


_ItemDescriptions.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.itemConfigEditMode] : productReducer[productStrings.itemConfigEditMode],
    [productStrings.productDescriptions] : productReducer[productStrings.productDescriptions],
})


export const ItemDescriptions = connect(mapStateToProps)(withStyles(style)(_ItemDescriptions));
export {ItemDescriptions as default}