import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MyListCard } from '../../../../../includes';
import { ListItem, ListItemText, ListItemIcon } from '@material-ui/core';
import { Delete } from '@material-ui/icons';
import DescriptionValueAddFooter from '../DescriptionValueAddFooter';
const style = theme => ({
    root: {
        
    }
})
class _DescriptionOptionValueBox extends Component {
    constructor(props) {
        super(props);
        const {row, cellMap, getContext} = props;
        this.state = {
            // list : row[cellMap]            
        }
        if(getContext)
            getContext(this);
    }
    addValue = value => {
        let {list} = this.state;
        list = list ? [...list] : [];
        if(list && list.length !== 0){
            const lastId = list[0].id || 0;
            list.push({id : lastId + 1, name : value});
        }else list = [{id : 1, name : value}]
        this.setState({list});
    }
    deleteValue = prop => ()=>{
        const valueType = prop._id ? "_id" : "id";
        let {list} = this.state;
        list = list ? [...list] : [];
        const {item : listItem, index : listIndex} = list.getFirstObjectByPropValue(valueType, prop[valueType]) || {};
        if(listItem){
            list.splice(listIndex, 1);
        }
        this.setState({list});
    }
    render() {
        const {classes} = this.props;
        const {list} = this.state;
        return (
            <MyListCard
                list={list}
                component={props=>{
                    return <ListItem button>
                        <ListItemText>{props.name}</ListItemText>
                        <ListItemIcon style={{minWidth : 0}}>
                            <Delete onClick={this.deleteValue(props)} color="secondary"/>
                        </ListItemIcon>
                    </ListItem>
                }}
                footer={
                    <DescriptionValueAddFooter 
                        addValue={this.addValue.bind(this)}
                    />
                }
            />
        );
    }
}
_DescriptionOptionValueBox.propTypes = {
    classes : PropTypes.object.isRequired,
    row : PropTypes.object,
    cellMap : PropTypes.string,
    getContext : PropTypes.func,
};
export const DescriptionOptionValueBox = withStyles(style)(_DescriptionOptionValueBox);