import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { productActions } from '../../actions';
import { productStrings } from '../../config';
import { MyTable, EditableCellMapFormat } from '../../../../includes';


const style = theme => ({
    root: {
    }
})
class _ItemPackages extends Component {
    constructor(props) {
        super(props);
        this.state = {
            itemPackages : null,
            itemPackagesUnusable : null
        }
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        productActions.setConfigComponent(this)(dispatch);
        productActions.getItemPackages()(dispatch);
    }
    componentWillUnmount(){
        productActions.setProductConfigEditMode(false)(this.props.dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [productStrings.itemPackages] : itemPackages
        } = props;
        if(!state.itemPackagesUnusable && itemPackages){
            state.itemPackagesUnusable = itemPackages;
            state.itemPackages = itemPackages;
        }else if(JSON.stringify(state.itemPackagesUnusable) !==
        JSON.stringify(itemPackages)){
            state.itemPackagesUnusable = itemPackages;
            state.itemPackages = itemPackages;
        }
        return state;
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    render() {
        const {
            classes,
            [productStrings.itemConfigEditMode] : itemConfigEditMode
        } = this.props;
        let {itemPackages} = this.state;
        let header = ['ID', "Name", "Description"];
        let dataMap = ["_id", "name", "description"];
        if(itemConfigEditMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            itemPackages = itemPackages ? 
                [...itemPackages.map(
                    item => ({...item, delible : true, editable : true})
                ), {new : true}] : 
                [{new : true}]
        }
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={itemPackages}
                    CellMap={this.cellMapFormat({
                        skipEdit:["_id"]
                    })}
                    />
            </div>
        );
    }
}


_ItemPackages.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.itemConfigEditMode] : productReducer[productStrings.itemConfigEditMode],
    [productStrings.itemPackages] : productReducer[productStrings.itemPackages],
})


export const ItemPackages = connect(mapStateToProps)(withStyles(style)(_ItemPackages));
export {ItemPackages as default}