import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, EditableCellMapFormat, headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, HighlightedInfo } from '../../../../includes';
import { productStrings } from '../../config';
import { productActions } from '../../actions';
import { routeNamesInventory } from '../../../routeNames';


const style = theme => ({
    root: {
    }
})
class _Tags extends Component {
    constructor(props) {
        super(props);
        this.state = {
            productItemTags : null,
            productItemTagsUnusable : null
        }
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        productActions.getproductItemTags()(dispatch);
        productActions.setConfigComponent(this)(dispatch);
    }
    componentWillUnmount(){
        productActions.setProductConfigEditMode(false)(this.props.dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [productStrings.productItemTags] : productItemTags
        } = props;
        if(!state.productItemTagUnusable && productItemTags){
            state.productItemTags = productItemTags;
            state.productItemTagUnusable = productItemTags;
        }else if(JSON.stringify(state.productItemTagUnusable) !==
        JSON.stringify(productItemTags)){
            state.productItemTags = productItemTags;
            state.productItemTagUnusable = productItemTags; 
        }
        return state;
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    render() {
        const {
            classes,
            [productStrings.itemConfigEditMode] : itemConfigEditMode
        } = this.props;
        let {productItemTags} = this.state;
        let header = ["ID", "Name", "Descriptions"];
        let dataMap = ["_id", "name", "description"];
        if(itemConfigEditMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            productItemTags = productItemTags ? 
                [...productItemTags.map(
                    item=>({...item, delible : true, editable : true})
                ), {new : true}] : 
                [{new : true}];
        }
        return (
            <div className={classes.root}>
                {itemConfigEditMode && <HighlightedInfo>
                    Deleting a tag already in use will default the item tags to 'UNKNOWN'
                </HighlightedInfo>}
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={productItemTags||[]}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"]
                    })}
                />
            </div>
        );
    }
}


_Tags.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.itemConfigEditMode] : productReducer[productStrings.itemConfigEditMode],
    [productStrings.productItemTags] : productReducer[productStrings.productItemTags],
})


export const Tags = connect(mapStateToProps)(withStyles(style)(_Tags));
export {Tags as default}