import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, headerActions, headerStrings, mainStageHeaderAction, mainStageHeaderStrings, breadCrumbActions } from '../../../includes';
import { Tags } from './Tags';
import { ItemForms } from "./ItemForms";
import { ItemPackages } from './ItemPackages';
import { routeNamesInventory } from '../../routeNames';
import ItemConfigStageHeader from './ItemConfigStageHeader';
import { productActions } from '../actions';
import { ItemPackaging } from './ItemPackaging';
import { ItemDescriptions } from './ItemDescriptions';


const style = theme => ({
    root: {
    }
})
class _ItemConfiguration extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PRODUCT CONFIGURATION",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Product Configuration", path : routeNamesInventory.productConfig},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                ItemConfigStageHeader
            ]
        })(dispatch);

    }
    setInitialTabValue = tabValue =>{
        this.setState({tabValue});
        const {dispatch} = this.props;
        productActions.setItemConfigTabValue(tabValue)(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        description : "Descriptions",
                        itemPackaging : "Item Packaging",
                        tags : "Tags",
                        forms : "Forms",
                        packages : "Packages",
                    }}
                    getInitialTabValue={this.setInitialTabValue.bind(this)}
                    />
                <div style={{marginTop : 20}}>
                    {tabValue === "tags" && <Tags/>}
                    {tabValue === "forms" && <ItemForms/>}
                    {tabValue === "packages" && <ItemPackages/>}
                    {tabValue === "itemPackaging" && <ItemPackaging/>}
                    {tabValue === "description" && <ItemDescriptions/>}
                </div>
            </div>
        );
    }
}


_ItemConfiguration.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const ItemConfiguration = connect(mapStateToProps)(withStyles(style)(_ItemConfiguration));
export {ItemConfiguration as default}