import React, { Component } from 'react';
import PropTypes from 'prop-types';
import { FormGroup, FormControl, Button, TextField } from '@material-ui/core';

class DescriptionValueAddFooter extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : ""
        }
    }
    addValue = e => {
        this.props.addValue(
            this.state.data
        );
        this.setState({data: ""});
    }
    render() {
        const {data} = this.state;
        return (
            <FormGroup style={{padding : 10}}>
                <FormControl style={{flexDirection: "row", justifyContent : 'center'}}>
                    <TextField 
                        value={data}
                        onChange={e=>this.setState({data : e.target.value})}/>
                    <Button 
                        onClick={e=>this.addValue(e)} 
                        variant="outlined" color="primary">Add</Button>
                </FormControl>
            </FormGroup>
        );
    }
}

DescriptionValueAddFooter.propTypes = {
    addValue : PropTypes.func,
};

export default DescriptionValueAddFooter;