import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { Paper } from '@material-ui/core';
import { ArrowDownwardOutlined } from "@material-ui/icons";
import { colors } from "../../../../../../utils";
import { routeNamesInventory } from '../../../../routeNames';

const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
        padding : 10,
    },
    package : {
        margin : 5,
        border : "solid 2px " + colors.secondary,
        borderRadius : 10,
        padding : 10
    }
})
class _PackagingDisplay extends Component {
    render() {
        const {classes, packages, packaging} = this.props;
        console.log(packages, packaging);
        return (
            <Paper className={classes.root}>
                {packaging && packaging.itemPackageIds && packaging.itemPackageIds.map(
                    (packageId, index) => {
                        const {item} = packages.getFirstObjectByPropValue("_id", packageId) || {};
                        return item ?
                            <Fragment key={index}>
                                <div className={classes.package}>{item.name}</div>
                                {index !== packaging.itemPackageIds.length -1 && <ArrowDownwardOutlined/>}
                            </Fragment>:
                            null;
                    }
                )}
                {packaging && packaging.itemPackageIds && packaging.itemPackageIds.length !== 0 &&
                    <div><Link to={{pathname : routeNamesInventory.packagingItems_ + packaging._id}}>See items</Link> </div>}
            </Paper>
        );
    }
}


_PackagingDisplay.propTypes = {
    classes : PropTypes.object.isRequired,
    packages : PropTypes.array,
    packaging : PropTypes.object,
};
const mapStateToProps = state => ({
    state
})


export const PackagingDisplay = connect(mapStateToProps)(withStyles(style)(_PackagingDisplay));
export {PackagingDisplay as default}