import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { productActions } from '../../actions';
import { productStrings } from '../../config';
import PackagingDisplay from './PackagingDisplay/PackagingDisplay';
import { Grid } from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _ItemPackaging extends Component {
    constructor(props) {
        super(props);
        
        this.initialiseComponent();
    }
    
    initialiseComponent(){
        const {
            dispatch,
            [productStrings.itemPackages] : itemPackages
        } = this.props;
        productActions.setConfigComponent(this)(dispatch);
        productActions.getItemPackagings()(dispatch);
        if(!itemPackages) productActions.getItemPackages()(dispatch);
    }
    componentWillUnmount(){
        productActions.setProductConfigEditMode(false)(this.props.dispatch);
    }
    render() {
        const {
            classes,
            [productStrings.itemPackages] : itemPackages,
            [productStrings.itemPackagings] : itemPackagings,
        } = this.props;
        return (
            <Grid container spacing={2} className={classes.root}>
                {itemPackagings && itemPackagings.map(
                    (packaging, index)=>
                        <Grid key={index} item xs={6} sm={4} md={4} lg={2} xl={2}>
                            <PackagingDisplay
                                packages={itemPackages}
                                packaging={packaging}
                            />
                        </Grid>
                )}
            </Grid>
        );
    }
}


_ItemPackaging.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.itemConfigEditMode] : productReducer[productStrings.itemConfigEditMode],
    [productStrings.itemPackages] : productReducer[productStrings.itemPackages],
    [productStrings.itemPackagings] : productReducer[productStrings.itemPackagings],
})


export const ItemPackaging = connect(mapStateToProps)(withStyles(style)(_ItemPackaging));
export {ItemPackaging as default}