import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { productStrings, productActions} from '../config';
import { DefaultMainStageHeader } from '../../../includes';

const style = theme => ({
    root: {
    }
})
class _ItemConfigStageHeader extends Component {
    editBtnHandler = () => {
        const {
            dispatch,
            [productStrings.itemConfigEditMode] : itemConfigEditMode,
        }=this.props;
        if(itemConfigEditMode){

        }
        productActions.setProductConfigEditMode(!Boolean(itemConfigEditMode))(dispatch);
    }
    cancelEditHandler = () => {
        productActions.setProductConfigEditMode(false)(this.props.dispatch);
    }
    render() {
        const {
            classes, [productStrings.itemConfigEditMode] : itemTagEditMode
        } = this.props;
        return (
            <DefaultMainStageHeader
                editMode={itemTagEditMode}
                editBtnHandler={this.editBtnHandler.bind(this)}
                cancelEditHandler={this.cancelEditHandler.bind(this)}
                />
        );
    }
}


_ItemConfigStageHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.itemConfigEditMode] : productReducer[productStrings.itemConfigEditMode],
    [productStrings.itemConfigComponent] : productReducer[productStrings.itemConfigComponent],
})


export const ItemConfigStageHeader = connect(mapStateToProps)(withStyles(style)(_ItemConfigStageHeader));
export {ItemConfigStageHeader as default}