import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { productStrings } from '../../config';
import { productActions } from '../../actions';
import { MyTable, EditableCellMapFormat } from '../../../../includes';


const style = theme => ({
    root: {
    }
})
class _ItemForms extends Component {
    constructor(props) {
        super(props);
        this.state = {
            itemForms : null,
            itemFormsUnusable : null
        }
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {dispatch} = this.props;
        productActions.setConfigComponent(this)(dispatch);
        productActions.getItemForms()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [productStrings.itemForms] : itemForms
        } = props;
        if(!state.itemFormsUnusable && itemForms){
            state.itemFormsUnusable = itemForms;
            state.itemForms = itemForms;
        }else if(JSON.stringify(state.itemFormsUnusable) !==
        JSON.stringify(itemForms)){
            state.itemFormsUnusable = itemForms;
            state.itemForms = itemForms;
        }
        return state;
    }
    componentWillUnmount(){
        productActions.setProductConfigEditMode(false)(this.props.dispatch);
    }
    cellMapFormat=superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>
    render() {
        const {
            classes,
            [productStrings.itemConfigEditMode] : itemConfigEditMode
        } = this.props;
        let {itemForms} = this.state;
        let header = ["ID", "Forms", "Description"];
        let dataMap = ["_id", "name", "description"];
        if(itemConfigEditMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            itemForms = itemForms ? 
                [...itemForms.map(
                    item=>({...item, editable : true, delible : true})
                ), {new : true}] : 
                [{new : true}]
        }
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={itemForms}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id"]
                    })}
                    />
            </div>
        );
    }
}


_ItemForms.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({productReducer}) => ({
    [productStrings.itemForms] : productReducer[productStrings.itemForms],
    [productStrings.itemConfigEditMode] : productReducer[productStrings.itemConfigEditMode],
})


export const ItemForms = connect(mapStateToProps)(withStyles(style)(_ItemForms));
export {ItemForms as default}